// components/fields/Group.tsx

import React, {useCallback, useEffect, useImperativeHandle, useMemo, useState} from 'react';
import {type FieldArrayWithId, type FieldValues, useFieldArray} from 'react-hook-form';
import type {IFormElement, IGroup, UseFieldLogicElementProps} from "@lmb-it/kitsconcerto-types";
import {Box, Flex, HStack, Text} from "../../../../_compat";
import {Divider} from "@lmb-it/kitsconcertomobile";
import {Label} from "../../../../_compat";
import {FormRenderer} from "../../FormRenderer";

/**
 * Renders a repeatable group of fields (a field array), preserving all the logic
 * for default values, min/max repeats, and custom action buttons.
 */
export const Group = <T extends FieldValues>({
                                                 element,
                                                 control,
                                                 getValues,
                                                 groupField,
                                                 focusedField,
                                                 setFocusedField,
                                                 fieldLogic,
                                             }: UseFieldLogicElementProps<T>) => { // Ensure UseFieldLogicProps is updated to pass focus props
    // 1. Get the group's own dynamic state (visibility, layout, label) from the logic hook.
    const {isShown, label, elements} = fieldLogic;

    const [_focusedField, _setFocusedField] = useState<string>('');

    const groupElement = element as IGroup<T>;
    const {groupsSettings, helperText} = groupElement;

    // 2. Initialize react-hook-form's field array management.
    const fieldArray = useFieldArray({
        control,
        name: element.id as any,
    });
    const {fields, append, remove} = fieldArray;

    // console.log('hitted', element, {fields}, element.id)
    // 3. Process group settings with defaults, exactly like the original component.
    const settings = useMemo(() => ({
        grid: groupsSettings?.grid,
        repeatable: {
            minRepeats: groupsSettings?.repeatable?.minRepeats || 0,
            maxRepeats: groupsSettings?.repeatable?.maxRepeats || Infinity,
            plusButton: groupsSettings?.repeatable?.plusButton,
            minusButton: groupsSettings?.repeatable?.minusButton,
        },
        removeButtonRow: groupsSettings?.removeButtonRow,
    }), [groupsSettings]);

    // 4. Replicate the logic to build a default item object for new rows.
    const createDefaultItem = (): FieldValues => {
        const item: FieldValues = {};
        elements?.forEach(el => {
            if ("displayOnly" in el && el.displayOnly) return;

            if ("initialUri" in el) {
                item[el.id as string] = (el as any).initialUri;
            } else if ("initialValue" in el && el.initialValue !== undefined) {
                item[el.id as string] = el.initialValue;
            }
        });
        return item;
    };

    const handleAppend = (count = 1) => {
        const max = settings.repeatable.maxRepeats;

        if (max && fields.length >= max) {
            return;
        }
        const itemsToAdd = Array(count).fill(0).map(() => createDefaultItem());
        append(itemsToAdd as any, {shouldFocus: true});
    };

    const handleRemove = (index: number) => {
        if (fields.length > (settings.repeatable.minRepeats || 0)) {
            remove(index);
        }
    };
    useEffect(() => {
        const generateGroupElements = () => {
            const min = settings.repeatable.minRepeats || 0;
            if (fields.length < min) {
                const itemsToAppend = min - fields.length;
                // console.log({itemsToAppend, current: fields.length})

                handleAppend(itemsToAppend);
            }
        };

        // This pattern correctly avoids the infinite loop by not depending on `append` or `fields`.
        // The timeout gives react-hook-form time to initialize before we check the length.
        const timer = setTimeout(generateGroupElements, 100);
        return () => clearTimeout(timer);

    }, [element.id, settings.repeatable.minRepeats]); // Stable dependencies

    // 6. Replicate the `useImperativeHandle` logic to expose the ref.
    useImperativeHandle(groupsSettings?.ref, () => fieldArray, [fieldArray]);


    const reBuildElements = useCallback((field: FieldArrayWithId, index: number) => {
        return elements?.map((childElement) => {
            const toArray = Object.entries(field);

            const findField = toArray.find(([name]) => name == childElement.id);

            return {
                ...childElement,
                initialValue: findField ? findField[1] : undefined,
            };
        }) as IFormElement<any>[];
    }, [element, elements]);


    if (!isShown) {
        return null;
    }

    return (
        <Flex id={element.id.toString()} w="full" flexDirection="column" gap={10} mb={6}>
            {label && (
                <Box mt={15} mb={15} w={'100%'}>
                    <Label as="h2" label={label} elementId={element.id.toString()}/>
                    <Divider style={{width:'100%'}} className="my-2" />
                </Box>
            )}

            {fields.map((field, index) => (
                <Flex key={field.id} w="full" position="relative" flexDirection="column"
                      rowGap={10}
                      columnGap={10}>

                    <FormRenderer
                        elements={reBuildElements(field, index)}
                        control={control}
                        groupField={{
                            index,
                            name: element.id.toString(),
                            values: getValues()[element.id][index],
                            append: handleAppend,
                            remove: () => handleRemove(index),
                        }}
                        getValues={getValues}
                        parentPath={`${element.id.toString()}.${index}.`}
                        focusedField={_focusedField!}
                        setFocusedField={_setFocusedField!}
                        grid={groupsSettings?.grid}
                    />

                    {settings.removeButtonRow && (
                        <Box style={{zIndex: 1}}>
                            {settings.removeButtonRow(fields.length, () => handleRemove(index), index)}
                        </Box>
                    )}


                    {settings.repeatable.minusButton && fields.length > settings.repeatable.minRepeats && (
                        <Box style={{zIndex: 1}}>
                            {settings.repeatable.minusButton(fields.length, () => handleRemove(index))}
                        </Box>
                    )}
                </Flex>
            ))}

            {settings.repeatable.plusButton && (
                <Flex justifyContent="flex-start" w="full" mt={8}>
                    {settings.repeatable.plusButton(fields.length, handleAppend)}
                </Flex>
            )}

            {helperText && typeof helperText != "function" && (
                <Text fontSize={10} as={"small"}>
                    {helperText}
                </Text>
            )}
        </Flex>
    );
};

export default Group;
